contracts/access/RoleAccess.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {ProtocolErrors} from "../common/ProtocolErrors.sol";
import {ProtocolEvents} from "../common/ProtocolEvents.sol";

contract RoleAccess is ProtocolErrors, ProtocolEvents {
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant ARBITER_ROLE = keccak256("ARBITER_ROLE");
    bytes32 public constant SELLER_MANAGER_ROLE = keccak256("SELLER_MANAGER_ROLE");

    address public owner;
    mapping(bytes32 => mapping(address => bool)) private roleMembers;

    modifier onlyOwner() {
        if (msg.sender != owner) revert Unauthorized();
        _;
    }

    modifier onlyRole(bytes32 role) {
        if (!hasRole(role, msg.sender)) revert Unauthorized();
        _;
    }

    modifier onlyOwnerOrRole(bytes32 role) {
        if (msg.sender != owner && !hasRole(role, msg.sender)) revert Unauthorized();
        _;
    }

    constructor() {
        owner = msg.sender;
        roleMembers[ADMIN_ROLE][msg.sender] = true;
        emit OwnerTransferred(address(0), msg.sender);
        emit RoleUpdated(ADMIN_ROLE, msg.sender, true);
    }

    function hasRole(bytes32 role, address account) public view returns (bool) {
        return roleMembers[role][account];
    }

    function setRole(bytes32 role, address account, bool enabled) external onlyOwner {
        if (account == address(0)) revert InvalidAddress();
        roleMembers[role][account] = enabled;
        emit RoleUpdated(role, account, enabled);
    }

    function transferOwnership(address newOwner) external onlyOwner {
        if (newOwner == address(0)) revert InvalidAddress();
        address previousOwner = owner;
        owner = newOwner;
        roleMembers[ADMIN_ROLE][newOwner] = true;
        emit OwnerTransferred(previousOwner, newOwner);
        emit RoleUpdated(ADMIN_ROLE, newOwner, true);
    }
}

contracts/common/ProtocolErrors.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

abstract contract ProtocolErrors {
    error Unauthorized();
    error InvalidAddress();
    error InvalidAmount();
    error InvalidStatus();
    error InvalidDeadline();
    error AlreadyExists();
    error NotFound();
    error TransferFailed();
    error ProductInactive();
    error InvalidPaymentToken();
    error EscrowExpired();
    error NotEscrowParty();
}

contracts/common/ProtocolEvents.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

abstract contract ProtocolEvents {
    event OwnerTransferred(address indexed previousOwner, address indexed newOwner);
    event RoleUpdated(bytes32 indexed role, address indexed account, bool enabled);

    event ProductCreated(
        uint256 indexed productId,
        string externalId,
        address indexed owner,
        address acceptedToken,
        uint256 unitPrice
    );
    event ProductUpdated(
        uint256 indexed productId,
        string metadataHash,
        address acceptedToken,
        uint256 unitPrice,
        bool active
    );
    event ProductOwnershipTransferred(uint256 indexed productId, address indexed previousOwner, address indexed newOwner);

    event EscrowCreated(
        bytes32 indexed escrowId,
        uint256 indexed productId,
        address indexed buyer,
        address seller,
        address paymentToken,
        uint256 amount
    );
    event EscrowFunded(bytes32 indexed escrowId, address indexed payer, uint256 amount);
    event EscrowDelivered(bytes32 indexed escrowId);
    event EscrowCompleted(bytes32 indexed escrowId, address indexed seller, uint256 amount);
    event EscrowDisputed(bytes32 indexed escrowId, address indexed raisedBy, string reason);
    event EscrowResolved(bytes32 indexed escrowId, uint256 sellerAmount, uint256 buyerAmount);
    event EscrowCancelled(bytes32 indexed escrowId);
}

