// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract OrderEscrow {
    enum Status {
        None,
        Funded,
        Released,
        Refunded
    }

    struct EscrowOrder {
        address buyer;
        address seller;
        uint256 amount;
        Status status;
        uint256 createdAt;
    }

    mapping(bytes32 => EscrowOrder) public orders;
    address public owner;

    event OrderFunded(bytes32 indexed orderId, address indexed buyer, address indexed seller, uint256 amount);
    event OrderReleased(bytes32 indexed orderId, address indexed seller, uint256 amount);
    event OrderRefunded(bytes32 indexed orderId, address indexed buyer, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Owner only");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function fundOrder(bytes32 orderId, address seller) external payable {
        require(orderId != bytes32(0), "Invalid order ID");
        require(seller != address(0), "Invalid seller");
        require(msg.value > 0, "Amount required");

        EscrowOrder storage order = orders[orderId];
        require(order.status == Status.None, "Order already exists");

        orders[orderId] = EscrowOrder({
            buyer: msg.sender,
            seller: seller,
            amount: msg.value,
            status: Status.Funded,
            createdAt: block.timestamp
        });

        emit OrderFunded(orderId, msg.sender, seller, msg.value);
    }

    function releaseToSeller(bytes32 orderId) external {
        EscrowOrder storage order = orders[orderId];
        require(order.status == Status.Funded, "Order not funded");
        require(msg.sender == order.buyer || msg.sender == owner, "Not authorized");

        order.status = Status.Released;
        (bool success, ) = payable(order.seller).call{value: order.amount}("");
        require(success, "Transfer failed");

        emit OrderReleased(orderId, order.seller, order.amount);
    }

    function refundToBuyer(bytes32 orderId) external onlyOwner {
        EscrowOrder storage order = orders[orderId];
        require(order.status == Status.Funded, "Order not funded");

        order.status = Status.Refunded;
        (bool success, ) = payable(order.buyer).call{value: order.amount}("");
        require(success, "Refund failed");

        emit OrderRefunded(orderId, order.buyer, order.amount);
    }
}

contracts/ProductRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract ProductRegistry {
    struct Product {
        string externalId;
        string metadataHash;
        address owner;
        uint256 createdAt;
    }

    mapping(bytes32 => Product) private products;

    event ProductRegistered(
        bytes32 indexed productKey,
        string externalId,
        string metadataHash,
        address indexed owner,
        uint256 createdAt
    );

    function registerProduct(
        string calldata externalId,
        string calldata metadataHash
    ) external returns (bytes32 productKey) {
        require(bytes(externalId).length > 0, "External ID required");
        require(bytes(metadataHash).length > 0, "Metadata hash required");

        productKey = keccak256(abi.encodePacked(externalId));
        require(products[productKey].createdAt == 0, "Product already exists");

        products[productKey] = Product({
            externalId: externalId,
            metadataHash: metadataHash,
            owner: msg.sender,
            createdAt: block.timestamp
        });

        emit ProductRegistered(
            productKey,
            externalId,
            metadataHash,
            msg.sender,
            block.timestamp
        );
    }

    function getProduct(bytes32 productKey) external view returns (Product memory) {
        require(products[productKey].createdAt != 0, "Product not found");
        return products[productKey];
    }
}

contracts/registry/ProductRegistryV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import {RoleAccess} from "../access/RoleAccess.sol";
import {ProtocolTypes} from "../common/ProtocolTypes.sol";
import {IProductRegistry} from "../interfaces/IProductRegistry.sol";

contract ProductRegistryV2 is RoleAccess, IProductRegistry {
    uint256 private nextProductId = 1;

    mapping(uint256 => ProtocolTypes.Product) private products;
    mapping(bytes32 => uint256) public productIdByExternalHash;

    function createProduct(
        string calldata externalId,
        string calldata metadataHash,
        address acceptedToken,
        uint256 unitPrice
    ) external returns (uint256 productId) {
        if (bytes(externalId).length == 0 || bytes(metadataHash).length == 0) revert InvalidAmount();
        if (unitPrice == 0) revert InvalidAmount();

        bytes32 externalHash = keccak256(abi.encodePacked(externalId));
        if (productIdByExternalHash[externalHash] != 0) revert AlreadyExists();

        productId = nextProductId++;
        products[productId] = ProtocolTypes.Product({
            id: productId,
            externalId: externalId,
            metadataHash: metadataHash,
            owner: msg.sender,
            acceptedToken: acceptedToken,
            unitPrice: unitPrice,
            active: true,
            createdAt: block.timestamp,
            updatedAt: block.timestamp
        });
        productIdByExternalHash[externalHash] = productId;

        emit ProductCreated(productId, externalId, msg.sender, acceptedToken, unitPrice);
    }

    function updateProduct(
        uint256 productId,
        string calldata metadataHash,
        address acceptedToken,
        uint256 unitPrice,
        bool active
    ) external {
        ProtocolTypes.Product storage product = products[productId];
        if (product.id == 0) revert NotFound();
        if (product.owner != msg.sender && !hasRole(ADMIN_ROLE, msg.sender)) revert Unauthorized();
        if (bytes(metadataHash).length == 0 || unitPrice == 0) revert InvalidAmount();

        product.metadataHash = metadataHash;
        product.acceptedToken = acceptedToken;
        product.unitPrice = unitPrice;
        product.active = active;
        product.updatedAt = block.timestamp;

        emit ProductUpdated(productId, metadataHash, acceptedToken, unitPrice, active);
    }

    function transferProductOwnership(uint256 productId, address newOwner) external {
        if (newOwner == address(0)) revert InvalidAddress();
        ProtocolTypes.Product storage product = products[productId];
        if (product.id == 0) revert NotFound();
        if (product.owner != msg.sender && !hasRole(SELLER_MANAGER_ROLE, msg.sender)) revert Unauthorized();

        address previousOwner = product.owner;
        product.owner = newOwner;
        product.updatedAt = block.timestamp;
        emit ProductOwnershipTransferred(productId, previousOwner, newOwner);
    }

    function getProduct(uint256 productId) external view returns (ProtocolTypes.Product memory) {
        ProtocolTypes.Product memory product = products[productId];
        if (product.id == 0) revert NotFound();
        return product;
    }

    function productExists(uint256 productId) external view returns (bool) {
        return products[productId].id != 0;
    }
}

contracts/SimpleAccess.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

contract SimpleAccess {
    address public owner;
    mapping(address => bool) public admins;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event AdminUpdated(address indexed admin, bool enabled);

    modifier onlyOwner() {
        require(msg.sender == owner, "Owner only");
        _;
    }

    modifier onlyOwnerOrAdmin() {
        require(msg.sender == owner || admins[msg.sender], "Not authorized");
        _;
    }

    constructor() {
        owner = msg.sender;
        emit OwnershipTransferred(address(0), msg.sender);
    }

    function setAdmin(address admin, bool enabled) external onlyOwner {
        require(admin != address(0), "Invalid admin");
        admins[admin] = enabled;
        emit AdminUpdated(admin, enabled);
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Invalid owner");
        address previousOwner = owner;
        owner = newOwner;
        emit OwnershipTransferred(previousOwner, newOwner);
    }
}

